// Valida a assinatura X-Platform-Signature (HMAC SHA-256 sobre o body bruto) com
// o segredo partilhado N8N_WEBHOOK_SECRET (configurado nas Credenciais do n8n
// como "Header Auth" OU, nesta versão minimalista, aqui no Code via env).
//
// O ideal é guardar o segredo em Credentials do n8n; para simplicidade, este
// fluxo lê de uma variável `SHARED_SECRET` definida em Settings → Variables.

const crypto = require('crypto');

const item = $input.first();
const headers = item.json.headers || {};
const rawBody = item.json.body;           // string bruta (rawBody: true)
const providedSig = (headers['x-platform-signature'] || '').trim();

const secret = $vars.SHARED_SECRET || $env.SHARED_SECRET;
if (!secret) {
  throw new Error('SHARED_SECRET não está configurado nas variáveis do n8n');
}

const expected = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
const ok = providedSig.length === expected.length &&
  crypto.timingSafeEqual(Buffer.from(providedSig, 'utf8'), Buffer.from(expected, 'utf8'));

if (!ok) {
  return [{ json: { __invalid_signature: true } }];
}

const parsed = JSON.parse(rawBody);
// Devolve os items um-a-um (para o SplitInBatches seguinte iterar)
return parsed.items.map(it => ({
  json: {
    dispatch_id: parsed.dispatch_id,
    callback_url: parsed.callback.url,
    signature_header: parsed.callback.signature_header,
    ...it
  }
}));

// Constrói o body do callback a partir da resposta da Meta e assina-o.
const crypto = require('crypto');
const secret = $vars.SHARED_SECRET || $env.SHARED_SECRET;
if (!secret) throw new Error('SHARED_SECRET em falta');

const input = $input.first().json;
// O HTTP anterior pode vir como { messages: [{ id }] } (sucesso) ou { error: {...} } (falha)
const metaResp = input.body || input;
const meta = metaResp;

const previousItem = $node['Loop Over Items'].json;

let status = 'failed';
let whatsapp_message_id = null;
let error = null;

if (meta && meta.messages && Array.isArray(meta.messages) && meta.messages[0] && meta.messages[0].id) {
  status = 'sent';
  whatsapp_message_id = meta.messages[0].id;
} else if (meta && meta.error) {
  error = meta.error.message || JSON.stringify(meta.error);
} else {
  error = 'Resposta Meta inesperada: ' + JSON.stringify(meta).slice(0, 300);
}

const callbackBody = JSON.stringify({
  queue_item_id: previousItem.queue_item_id,
  dispatch_id: previousItem.dispatch_id,
  status,
  whatsapp_message_id,
  error
});

const signature = crypto.createHmac('sha256', secret).update(callbackBody).digest('hex');

return [{
  json: {
    callback_url: previousItem.callback_url,
    signature_header: previousItem.signature_header,
    signature,
    callback_body: callbackBody
  }
}];

// Provider não suportado nesta versão → callback "failed" para a plataforma
// desistir do item (e não ficar stuck em "sending").
const crypto = require('crypto');
const secret = $vars.SHARED_SECRET || $env.SHARED_SECRET;
if (!secret) throw new Error('SHARED_SECRET em falta');

const previousItem = $input.first().json;
const callbackBody = JSON.stringify({
  queue_item_id: previousItem.queue_item_id,
  dispatch_id: previousItem.dispatch_id,
  status: 'failed',
  whatsapp_message_id: null,
  error: `Provider '${previousItem.provider}' ainda não suportado no fluxo n8n — usar worker directo.`
});
const signature = crypto.createHmac('sha256', secret).update(callbackBody).digest('hex');

return [{
  json: {
    callback_url: previousItem.callback_url,
    signature_header: previousItem.signature_header,
    signature,
    callback_body: callbackBody
  }
}];
